#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum FanoRuntimeError {
    OutOfCarrier(u8),
    RootIsNotVisible,
    SelfCollisionExitsToRoot,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct FanoPoint(u8);

impl FanoPoint {
    pub fn new(state: u8) -> Result<Self, FanoRuntimeError> {
        if state > 7 {
            return Err(FanoRuntimeError::OutOfCarrier(state));
        }
        if state == GOD_POSITION {
            return Err(FanoRuntimeError::RootIsNotVisible);
        }
        Ok(Self(state))
    }

    #[inline(always)]
    pub const fn state(self) -> u8 {
        self.0
    }

    #[inline(always)]
    pub const fn aeon_column(self) -> u8 {
        self.0 - 1
    }
}

