impl From<MonsterFanoXorPayloadAdmission> for MonsterFanoXorPayloadRoute {
    fn from(admission: MonsterFanoXorPayloadAdmission) -> Self {
        match admission {
            MonsterFanoXorPayloadAdmission::Admitted(cert) => Self::Admitted {
                payload: cert.payload,
                aeon_gate: cert.aeon_gate,
            },
            MonsterFanoXorPayloadAdmission::SameAeonPhase { phase } => {
                Self::SameAeonPhase { phase }
            }
            MonsterFanoXorPayloadAdmission::OutsideFanoSubatlas { aeon_gate } => {
                Self::OutsideFanoSubatlas { aeon_gate }
            }
            MonsterFanoXorPayloadAdmission::ShadowValidationRequired { aeon_gate } => {
                Self::ShadowValidationRequired { aeon_gate }
            }
        }
    }
}

