#[derive(Clone, Debug)]
pub struct FanoMycelialRouteCache {
    fano_completions: [Option<u8>; 64],
    fano_routes: [Option<MonsterAeonFanoTemplate>; FANO_PAIR_GATE_COUNT],
    fano_packed_payload_routes: [Option<u16>; FANO_PAIR_GATE_COUNT],
    aeon_routes: [Option<MonsterAeonFanoTemplate>; FANO_AEON_PHASE_FLAG_CACHE_SLOTS],
    monster_routes: Vec<Option<(u64, MonsterAeonFanoProjection)>>,
    payload_monster_routes: Vec<Option<(u64, MonsterFanoXorPayloadAdmission)>>,
    stats: FanoMycelialRouteCacheStats,
}

impl Default for FanoMycelialRouteCache {
    fn default() -> Self {
        Self::new(4096)
    }
}

impl FanoMycelialRouteCache {
    pub fn new(max_monster_entries: usize) -> Self {
        // Round the monster route arenas up to a power of two so slot
        // selection is a single AND instead of an integer division — the
        // power-of-two mask identity the frame arena is certified for
        // (Lean: FoilMersenneHotPath.frame_arena_mask).
        let arena_entries = max_monster_entries.max(1).next_power_of_two();
        Self {
            fano_completions: [None; 64],
            fano_routes: [None; FANO_PAIR_GATE_COUNT],
            fano_packed_payload_routes: [None; FANO_PAIR_GATE_COUNT],
            aeon_routes: [None; FANO_AEON_PHASE_FLAG_CACHE_SLOTS],
            monster_routes: vec![None; arena_entries],
            payload_monster_routes: vec![None; arena_entries],
            stats: FanoMycelialRouteCacheStats::default(),
        }
    }

    /// Slot of a monster cache key: `key & (len − 1)` is exactly `key % len`
    /// because the arenas are power-of-two sized (Lean: `frame_arena_mask`
    /// proves the mask/mod identity at the frame arena's `2¹³`; the same
    /// identity holds for every power of two).
    #[inline(always)]
    fn monster_slot(key: u64, arena_len: usize) -> usize {
        (key as usize) & (arena_len - 1)
    }

    pub fn route_monster_aeon_fano(
        &mut self,
        lhs_column: u32,
        rhs_column: u32,
        residual_validated: bool,
        fingerprint_verified: bool,
    ) -> MonsterAeonFanoProjection {
        let lhs_phase = monster_column_phase(lhs_column);
        let rhs_phase = monster_column_phase(rhs_column);
        if residual_validated && fingerprint_verified {
            if let Some(fano_slot) = fano_phase_cache_key_rank(lhs_phase, rhs_phase) {
                if let Some(template) = self.fano_routes[fano_slot] {
                    self.stats.fano_route_hits += 1;
                    return self.materialize_template(template, lhs_column, rhs_column);
                }
                self.stats.fano_route_misses += 1;
                let projection = monster_aeon_fano_certificate(
                    lhs_column,
                    rhs_column,
                    residual_validated,
                    fingerprint_verified,
                );
                let template = self.template_from_projection(projection);
                self.fano_routes[fano_slot] = Some(template);
                return projection;
            }
        }

        let monster_key = fano_monster_pair_cache_key(
            lhs_column,
            rhs_column,
            residual_validated,
            fingerprint_verified,
        );
        let monster_slot = Self::monster_slot(monster_key, self.monster_routes.len());
        if let Some((cached_key, cached)) = self.monster_routes[monster_slot] {
            if cached_key == monster_key {
                self.stats.monster_hits += 1;
                return cached;
            }
        }
        self.stats.monster_misses += 1;

        let aeon_key = fano_aeon_phase_cache_key(
            lhs_phase,
            rhs_phase,
            residual_validated,
            fingerprint_verified,
        );
        let projection = if let Some(template) = self.aeon_routes[aeon_key as usize] {
            self.stats.aeon_hits += 1;
            self.materialize_template(template, lhs_column, rhs_column)
        } else {
            self.stats.aeon_misses += 1;
            let projection = monster_aeon_fano_certificate(
                lhs_column,
                rhs_column,
                residual_validated,
                fingerprint_verified,
            );
            let template = self.template_from_projection(projection);
            self.aeon_routes[aeon_key as usize] = Some(template);
            projection
        };

        self.monster_routes[monster_slot] = Some((monster_key, projection));
        projection
    }

    pub fn route_monster_fano_xor_payload(
        &mut self,
        lhs_column: u32,
        rhs_column: u32,
        residual_validated: bool,
        fingerprint_verified: bool,
    ) -> MonsterFanoXorPayloadAdmission {
        let lhs_phase = monster_column_phase(lhs_column);
        let rhs_phase = monster_column_phase(rhs_column);
        if residual_validated && fingerprint_verified {
            if let Some(fano_slot) = fano_phase_cache_key_rank(lhs_phase, rhs_phase) {
                if let Some(template) = self.fano_routes[fano_slot] {
                    self.stats.fano_route_hits += 1;
                    return self.materialize_payload_template(template, lhs_column, rhs_column);
                }
                self.stats.fano_route_misses += 1;
                let admission = admit_monster_fano_xor_payload(
                    lhs_column,
                    rhs_column,
                    residual_validated,
                    fingerprint_verified,
                );
                let template = self.template_from_payload_admission(admission);
                self.fano_routes[fano_slot] = Some(template);
                return admission;
            }
        }

        let monster_key = fano_monster_pair_cache_key(
            lhs_column,
            rhs_column,
            residual_validated,
            fingerprint_verified,
        );
        let monster_slot = Self::monster_slot(monster_key, self.payload_monster_routes.len());
        if let Some((cached_key, cached)) = self.payload_monster_routes[monster_slot] {
            if cached_key == monster_key {
                self.stats.payload_monster_hits += 1;
                return cached;
            }
        }
        self.stats.payload_monster_misses += 1;

        let aeon_key = fano_aeon_phase_cache_key(
            lhs_phase,
            rhs_phase,
            residual_validated,
            fingerprint_verified,
        );
        let admission = if let Some(template) = self.aeon_routes[aeon_key as usize] {
            self.stats.aeon_hits += 1;
            self.materialize_payload_template(template, lhs_column, rhs_column)
        } else {
            self.stats.aeon_misses += 1;
            let admission = admit_monster_fano_xor_payload(
                lhs_column,
                rhs_column,
                residual_validated,
                fingerprint_verified,
            );
            let template = self.template_from_payload_admission(admission);
            self.aeon_routes[aeon_key as usize] = Some(template);
            admission
        };

        self.payload_monster_routes[monster_slot] = Some((monster_key, admission));
        admission
    }

    pub fn route_monster_fano_xor_payload_packed(
        &mut self,
        lhs_column: u32,
        rhs_column: u32,
        residual_validated: bool,
        fingerprint_verified: bool,
    ) -> u16 {
        let lhs_phase = monster_column_phase(lhs_column);
        let rhs_phase = monster_column_phase(rhs_column);
        if residual_validated && fingerprint_verified {
            if let Some(fano_slot) = fano_phase_cache_key_rank(lhs_phase, rhs_phase) {
                if let Some(route) = self.fano_packed_payload_routes[fano_slot] {
                    self.stats.fano_route_hits += 1;
                    return route;
                }
                self.stats.fano_route_misses += 1;
                let route = pack_fano_xor_payload_route(
                    FANO_XOR_ROUTE_ADMITTED,
                    triton_collide(lhs_phase + 1, rhs_phase + 1),
                    lhs_phase.min(rhs_phase),
                    lhs_phase.max(rhs_phase),
                );
                self.fano_packed_payload_routes[fano_slot] = Some(route);
                return route;
            }
        }

        route_monster_fano_xor_payload_packed(
            lhs_column,
            rhs_column,
            residual_validated,
            fingerprint_verified,
        )
    }

    pub fn stats(&self) -> FanoMycelialRouteCacheStats {
        FanoMycelialRouteCacheStats {
            monster_entries: self
                .monster_routes
                .iter()
                .filter(|entry| entry.is_some())
                .count(),
            payload_monster_entries: self
                .payload_monster_routes
                .iter()
                .filter(|entry| entry.is_some())
                .count(),
            ..self.stats
        }
    }

    pub fn clear(&mut self) {
        self.fano_completions = [None; 64];
        self.fano_routes = [None; FANO_PAIR_GATE_COUNT];
        self.fano_packed_payload_routes = [None; FANO_PAIR_GATE_COUNT];
        self.aeon_routes = [None; FANO_AEON_PHASE_FLAG_CACHE_SLOTS];
        self.monster_routes.fill(None);
        self.payload_monster_routes.fill(None);
        self.stats = FanoMycelialRouteCacheStats::default();
    }

    fn template_from_projection(
        &mut self,
        projection: MonsterAeonFanoProjection,
    ) -> MonsterAeonFanoTemplate {
        match projection {
            MonsterAeonFanoProjection::Certified(cert) => {
                let fano_key = fano_completion_cache_key(cert.fano_states[0], cert.fano_states[1]);
                let completion = match self.fano_completions[fano_key as usize] {
                    Some(completion) => {
                        self.stats.fano_hits += 1;
                        completion
                    }
                    None => {
                        self.stats.fano_misses += 1;
                        let completion = triton_collide(cert.fano_states[0], cert.fano_states[1]);
                        self.fano_completions[fano_key as usize] = Some(completion);
                        completion
                    }
                };
                MonsterAeonFanoTemplate::Certified {
                    aeon_phases: cert.aeon_phases,
                    aeon_gate: cert.aeon_gate,
                    fano_states: cert.fano_states,
                    completion,
                    orientation_sign: cert.orientation_sign,
                    positive_gate: cert.positive_gate,
                    residual_validated: cert.residual_validated,
                    fingerprint_verified: cert.fingerprint_verified,
                }
            }
            MonsterAeonFanoProjection::SameAeonPhase { phase } => {
                MonsterAeonFanoTemplate::SameAeonPhase { phase }
            }
            MonsterAeonFanoProjection::OutsideFanoSubatlas { aeon_gate } => {
                MonsterAeonFanoTemplate::OutsideFanoSubatlas { aeon_gate }
            }
            MonsterAeonFanoProjection::ShadowValidationRequired { aeon_gate } => {
                MonsterAeonFanoTemplate::ShadowValidationRequired { aeon_gate }
            }
        }
    }

    fn materialize_template(
        &self,
        template: MonsterAeonFanoTemplate,
        lhs_column: u32,
        rhs_column: u32,
    ) -> MonsterAeonFanoProjection {
        match template {
            MonsterAeonFanoTemplate::Certified {
                aeon_phases,
                aeon_gate,
                fano_states,
                completion,
                orientation_sign,
                positive_gate,
                residual_validated,
                fingerprint_verified,
            } => MonsterAeonFanoProjection::Certified(MonsterAeonFanoCertificate {
                monster_columns: [lhs_column, rhs_column],
                aeon_phases,
                aeon_gate,
                fano_states,
                completion,
                orientation_sign,
                positive_gate,
                residual_validated,
                fingerprint_verified,
                theorem_refs: FANO_RUNTIME_THEOREM_REFS,
            }),
            MonsterAeonFanoTemplate::SameAeonPhase { phase } => {
                MonsterAeonFanoProjection::SameAeonPhase { phase }
            }
            MonsterAeonFanoTemplate::OutsideFanoSubatlas { aeon_gate } => {
                MonsterAeonFanoProjection::OutsideFanoSubatlas { aeon_gate }
            }
            MonsterAeonFanoTemplate::ShadowValidationRequired { aeon_gate } => {
                MonsterAeonFanoProjection::ShadowValidationRequired { aeon_gate }
            }
        }
    }

    fn template_from_payload_admission(
        &mut self,
        admission: MonsterFanoXorPayloadAdmission,
    ) -> MonsterAeonFanoTemplate {
        match admission {
            MonsterFanoXorPayloadAdmission::Admitted(cert) => {
                let fano_key = fano_completion_cache_key(cert.fano_states[0], cert.fano_states[1]);
                let completion = match self.fano_completions[fano_key as usize] {
                    Some(completion) => {
                        self.stats.fano_hits += 1;
                        completion
                    }
                    None => {
                        self.stats.fano_misses += 1;
                        self.fano_completions[fano_key as usize] = Some(cert.payload);
                        cert.payload
                    }
                };
                MonsterAeonFanoTemplate::Certified {
                    aeon_phases: cert.aeon_phases,
                    aeon_gate: cert.aeon_gate,
                    fano_states: cert.fano_states,
                    completion,
                    orientation_sign: if cert.aeon_phases[0] < cert.aeon_phases[1] {
                        1
                    } else {
                        -1
                    },
                    positive_gate: true,
                    residual_validated: cert.residual_validated,
                    fingerprint_verified: cert.fingerprint_verified,
                }
            }
            MonsterFanoXorPayloadAdmission::SameAeonPhase { phase } => {
                MonsterAeonFanoTemplate::SameAeonPhase { phase }
            }
            MonsterFanoXorPayloadAdmission::OutsideFanoSubatlas { aeon_gate } => {
                MonsterAeonFanoTemplate::OutsideFanoSubatlas { aeon_gate }
            }
            MonsterFanoXorPayloadAdmission::ShadowValidationRequired { aeon_gate } => {
                MonsterAeonFanoTemplate::ShadowValidationRequired { aeon_gate }
            }
        }
    }

    fn materialize_payload_template(
        &self,
        template: MonsterAeonFanoTemplate,
        lhs_column: u32,
        rhs_column: u32,
    ) -> MonsterFanoXorPayloadAdmission {
        match template {
            MonsterAeonFanoTemplate::Certified {
                aeon_phases,
                aeon_gate,
                fano_states,
                completion,
                residual_validated,
                fingerprint_verified,
                ..
            } => MonsterFanoXorPayloadAdmission::Admitted(
                MonsterFanoXorPayloadAdmissionCertificate {
                    monster_columns: [lhs_column, rhs_column],
                    aeon_phases,
                    aeon_gate,
                    fano_states,
                    payload: completion,
                    residual_validated,
                    fingerprint_verified,
                    theorem_refs: FANO_RUNTIME_THEOREM_REFS,
                },
            ),
            MonsterAeonFanoTemplate::SameAeonPhase { phase } => {
                MonsterFanoXorPayloadAdmission::SameAeonPhase { phase }
            }
            MonsterAeonFanoTemplate::OutsideFanoSubatlas { aeon_gate } => {
                MonsterFanoXorPayloadAdmission::OutsideFanoSubatlas { aeon_gate }
            }
            MonsterAeonFanoTemplate::ShadowValidationRequired { aeon_gate } => {
                MonsterFanoXorPayloadAdmission::ShadowValidationRequired { aeon_gate }
            }
        }
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum FanoOperationKind {
    BinaryProjectiveRoute,
    ResidualSeedShadow,
    PluckerSignLift,
    PositiveGateShadow,
    FullGrassmannianTransform,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum FanoAdmissionDecision {
    AdmitXor,
    ShadowOnly,
    Deny,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum FanoAdmissionReason {
    BinaryProjectiveShadow,
    PluckerSignShadow,
    PositiveGateShadow,
    ShadowValidationRequired,
    RootOperand,
    SelfCollisionExitsToRoot,
    OutOfCarrier,
    HigherStructureNotProjected,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct FanoAdmissionRequest {
    pub op: FanoOperationKind,
    pub lhs: u8,
    pub rhs: u8,
    pub shadow_validation: bool,
    pub fingerprint_verified: bool,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct FanoAdmissionWitness {
    pub decision: FanoAdmissionDecision,
    pub reason: FanoAdmissionReason,
    pub collision: Option<FanoCollision>,
    pub pair_gate: Option<[u8; 2]>,
    pub oriented_pair: Option<FanoOrientedPairCertificate>,
    pub residual_shadow: Option<FanoResidualShadowCertificate>,
    pub theorem_refs: &'static [&'static str],
}

#[inline(always)]
pub const fn triton_collide(lhs: u8, rhs: u8) -> u8 {
    (lhs ^ rhs) & 0b111
}

pub fn fano_complete(lhs: FanoPoint, rhs: FanoPoint) -> Result<FanoPoint, FanoRuntimeError> {
    let completion = triton_collide(lhs.state(), rhs.state());
    if completion == GOD_POSITION {
        return Err(FanoRuntimeError::SelfCollisionExitsToRoot);
    }
    FanoPoint::new(completion)
}

#[inline(always)]
pub fn fano_collision(lhs: u8, rhs: u8) -> Result<FanoCollision, FanoRuntimeError> {
    if lhs > 7 {
        return Err(FanoRuntimeError::OutOfCarrier(lhs));
    }
    if rhs > 7 {
        return Err(FanoRuntimeError::OutOfCarrier(rhs));
    }
    let completion = triton_collide(lhs, rhs);
    Ok(FanoCollision {
        lhs,
        rhs,
        completion,
        exits_to_root: completion == GOD_POSITION,
    })
}

pub fn fano_pair_gate(lhs: FanoPoint, rhs: FanoPoint) -> Result<[u8; 2], FanoRuntimeError> {
    if lhs == rhs {
        return Err(FanoRuntimeError::SelfCollisionExitsToRoot);
    }
    let a = lhs.aeon_column();
    let b = rhs.aeon_column();
    Ok(if a < b { [a, b] } else { [b, a] })
}

#[inline(always)]
pub const fn fano_phase_cache_key_rank(lhs_phase: u8, rhs_phase: u8) -> Option<usize> {
    if lhs_phase >= AEON_FANO_VISIBLE_PHASES
        || rhs_phase >= AEON_FANO_VISIBLE_PHASES
        || lhs_phase == rhs_phase
    {
        return None;
    }
    let (i, j) = if lhs_phase < rhs_phase {
        (lhs_phase as usize, rhs_phase as usize)
    } else {
        (rhs_phase as usize, lhs_phase as usize)
    };
    Some(i * (13 - i) / 2 + (j - (i + 1)))
}

pub fn fano_pair_xor_runtime_stack(
    lhs: FanoPoint,
    rhs: FanoPoint,
) -> Result<[Option<u8>; AEON_GR_2_12_GATE_COUNT], FanoRuntimeError> {
    let gate = fano_pair_gate(lhs, rhs)?;
    let completion = triton_collide(lhs.state(), rhs.state());
    let mut stack = [None; AEON_GR_2_12_GATE_COUNT];
    let mut index = 0usize;
    for j in 1..AEON_GR_2_12_AMBIENT_DIM {
        for i in 0..j {
            if [i, j] == gate {
                stack[index] = Some(completion);
            }
            index += 1;
        }
    }
    Ok(stack)
}

pub fn fano_pair_xor_runtime_stack_payload_count(
    stack: &[Option<u8>; AEON_GR_2_12_GATE_COUNT],
) -> usize {
    stack.iter().filter(|payload| payload.is_some()).count()
}

#[inline(always)]
pub const fn monster_column_phase(column: u32) -> u8 {
    (column % (AEON_GR_2_12_AMBIENT_DIM as u32)) as u8
}

pub fn monster_pair_to_aeon_gate(lhs: u32, rhs: u32) -> Option<[u8; 2]> {
    monster_phase_pair_to_aeon_gate(monster_column_phase(lhs), monster_column_phase(rhs))
}

/// Aeon gate from already-split phases — the no-mod hot path. Callers that
/// have computed (or stored) the column phases never re-derive `% 12` here:
/// the equal-phase early-out is the FIRST compare, and equal phases provably
/// gate to `none` (Lean: `GriessAeonMeshDescent.mesh_cannot_resolve_griess_bands`;
/// `FoilMersenneHotPath.aeon_split_roundtrip` makes the ingest split lossless).
#[inline(always)]
pub const fn monster_phase_pair_to_aeon_gate(lhs_phase: u8, rhs_phase: u8) -> Option<[u8; 2]> {
    if lhs_phase == rhs_phase {
        None
    } else if lhs_phase < rhs_phase {
        Some([lhs_phase, rhs_phase])
    } else {
        Some([rhs_phase, lhs_phase])
    }
}

#[inline(always)]
pub const fn aeon_phase_to_fano_state(phase: u8) -> Option<u8> {
    if phase < AEON_FANO_VISIBLE_PHASES {
        Some(phase + 1)
    } else {
        None
    }
}

pub fn monster_aeon_fano_certificate(
    lhs_column: u32,
    rhs_column: u32,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> MonsterAeonFanoProjection {
    let lhs_phase = monster_column_phase(lhs_column);
    let rhs_phase = monster_column_phase(rhs_column);

    let Some(aeon_gate) = monster_phase_pair_to_aeon_gate(lhs_phase, rhs_phase) else {
        return MonsterAeonFanoProjection::SameAeonPhase { phase: lhs_phase };
    };

    let (Some(lhs_state), Some(rhs_state)) = (
        aeon_phase_to_fano_state(lhs_phase),
        aeon_phase_to_fano_state(rhs_phase),
    ) else {
        return MonsterAeonFanoProjection::OutsideFanoSubatlas { aeon_gate };
    };

    if !(residual_validated && fingerprint_verified) {
        return MonsterAeonFanoProjection::ShadowValidationRequired { aeon_gate };
    }

    let lhs = FanoPoint::new(lhs_state).expect("phase-to-state maps to a visible Fano point");
    let rhs = FanoPoint::new(rhs_state).expect("phase-to-state maps to a visible Fano point");
    let oriented =
        fano_oriented_pair_certificate(lhs, rhs).expect("distinct Aeon phases are distinct states");

    MonsterAeonFanoProjection::Certified(MonsterAeonFanoCertificate {
        monster_columns: [lhs_column, rhs_column],
        aeon_phases: [lhs_phase, rhs_phase],
        aeon_gate,
        fano_states: [lhs_state, rhs_state],
        completion: oriented.completion,
        orientation_sign: oriented.orientation_sign,
        positive_gate: oriented.positive_gate,
        residual_validated,
        fingerprint_verified,
        theorem_refs: FANO_RUNTIME_THEOREM_REFS,
    })
}

pub fn admit_monster_fano_xor_payload(
    lhs_column: u32,
    rhs_column: u32,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> MonsterFanoXorPayloadAdmission {
    let lhs_phase = monster_column_phase(lhs_column);
    let rhs_phase = monster_column_phase(rhs_column);

    let Some(aeon_gate) = monster_phase_pair_to_aeon_gate(lhs_phase, rhs_phase) else {
        return MonsterFanoXorPayloadAdmission::SameAeonPhase { phase: lhs_phase };
    };

    let (Some(lhs_state), Some(rhs_state)) = (
        aeon_phase_to_fano_state(lhs_phase),
        aeon_phase_to_fano_state(rhs_phase),
    ) else {
        return MonsterFanoXorPayloadAdmission::OutsideFanoSubatlas { aeon_gate };
    };

    if !(residual_validated && fingerprint_verified) {
        return MonsterFanoXorPayloadAdmission::ShadowValidationRequired { aeon_gate };
    }

    MonsterFanoXorPayloadAdmission::Admitted(MonsterFanoXorPayloadAdmissionCertificate {
        monster_columns: [lhs_column, rhs_column],
        aeon_phases: [lhs_phase, rhs_phase],
        aeon_gate,
        fano_states: [lhs_state, rhs_state],
        payload: triton_collide(lhs_state, rhs_state),
        residual_validated,
        fingerprint_verified,
        theorem_refs: FANO_RUNTIME_THEOREM_REFS,
    })
}

#[inline(always)]
pub fn route_monster_fano_xor_payload(
    lhs_column: u32,
    rhs_column: u32,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> MonsterFanoXorPayloadRoute {
    let lhs_phase = monster_column_phase(lhs_column);
    let rhs_phase = monster_column_phase(rhs_column);

    let Some(aeon_gate) = monster_phase_pair_to_aeon_gate(lhs_phase, rhs_phase) else {
        return MonsterFanoXorPayloadRoute::SameAeonPhase { phase: lhs_phase };
    };

    if lhs_phase >= AEON_FANO_VISIBLE_PHASES || rhs_phase >= AEON_FANO_VISIBLE_PHASES {
        return MonsterFanoXorPayloadRoute::OutsideFanoSubatlas { aeon_gate };
    }

    if !(residual_validated && fingerprint_verified) {
        return MonsterFanoXorPayloadRoute::ShadowValidationRequired { aeon_gate };
    }

    MonsterFanoXorPayloadRoute::Admitted {
        payload: triton_collide(lhs_phase + 1, rhs_phase + 1),
        aeon_gate,
    }
}

#[inline(always)]
pub fn route_monster_fano_xor_payload_with_policy(
    policy: MonsterFanoXorPayloadDispatchPolicy,
    cache: Option<&mut FanoMycelialRouteCache>,
    lhs_column: u32,
    rhs_column: u32,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> MonsterFanoXorPayloadRoute {
    match (policy, cache) {
        (MonsterFanoXorPayloadDispatchPolicy::ExactHotCached, Some(cache)) => {
            fano_xor_payload_route_unpack(cache.route_monster_fano_xor_payload_packed(
                lhs_column,
                rhs_column,
                residual_validated,
                fingerprint_verified,
            ))
        }
        _ => route_monster_fano_xor_payload(
            lhs_column,
            rhs_column,
            residual_validated,
            fingerprint_verified,
        ),
    }
}

pub fn route_monster_fano_xor_payload_packed_with_policy(
    policy: MonsterFanoXorPayloadDispatchPolicy,
    cache: Option<&mut FanoMycelialRouteCache>,
    lhs_column: u32,
    rhs_column: u32,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> u16 {
    match (policy, cache) {
        (MonsterFanoXorPayloadDispatchPolicy::ExactHotCached, Some(cache)) => cache
            .route_monster_fano_xor_payload_packed(
                lhs_column,
                rhs_column,
                residual_validated,
                fingerprint_verified,
            ),
        _ => route_monster_fano_xor_payload_packed(
            lhs_column,
            rhs_column,
            residual_validated,
            fingerprint_verified,
        ),
    }
}

#[inline(always)]
pub fn route_monster_fano_xor_payload_default_packed(
    cache: &mut FanoMycelialRouteCache,
    lhs_column: u32,
    rhs_column: u32,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> u16 {
    cache.route_monster_fano_xor_payload_packed(
        lhs_column,
        rhs_column,
        residual_validated,
        fingerprint_verified,
    )
}

#[inline(always)]
pub const fn pack_monster_fano_xor_payload_route(route: MonsterFanoXorPayloadRoute) -> u16 {
    match route {
        MonsterFanoXorPayloadRoute::Admitted { payload, aeon_gate } => pack_fano_xor_payload_route(
            FANO_XOR_ROUTE_ADMITTED,
            payload,
            aeon_gate[0],
            aeon_gate[1],
        ),
        MonsterFanoXorPayloadRoute::SameAeonPhase { phase } => {
            pack_fano_xor_payload_route(FANO_XOR_ROUTE_SAME_PHASE, phase, 0, 0)
        }
        MonsterFanoXorPayloadRoute::OutsideFanoSubatlas { aeon_gate } => {
            pack_fano_xor_payload_route(
                FANO_XOR_ROUTE_OUTSIDE_SUBATLAS,
                0,
                aeon_gate[0],
                aeon_gate[1],
            )
        }
        MonsterFanoXorPayloadRoute::ShadowValidationRequired { aeon_gate } => {
            pack_fano_xor_payload_route(
                FANO_XOR_ROUTE_SHADOW_REQUIRED,
                0,
                aeon_gate[0],
                aeon_gate[1],
            )
        }
    }
}

#[inline(always)]
pub const fn monster_fano_xor_payload_route_hint(
    lhs_column: u32,
    rhs_column: u32,
    route: MonsterFanoXorPayloadRoute,
) -> u8 {
    match route {
        MonsterFanoXorPayloadRoute::Admitted { .. } => {
            if lhs_column <= rhs_column {
                FANO_XOR_ROUTE_HINT_POSITIVE
            } else {
                FANO_XOR_ROUTE_HINT_NEGATIVE
            }
        }
        MonsterFanoXorPayloadRoute::SameAeonPhase { .. } => FANO_XOR_ROUTE_HINT_ZERO_ROOT,
        _ => FANO_XOR_ROUTE_HINT_NONE,
    }
}

#[inline(always)]
pub fn pack_monster_fano_xor_payload_route_with_hint(
    lhs_column: u32,
    rhs_column: u32,
    route: MonsterFanoXorPayloadRoute,
) -> u16 {
    let hint = monster_fano_xor_payload_route_hint(lhs_column, rhs_column, route);
    match route {
        MonsterFanoXorPayloadRoute::Admitted { payload, aeon_gate } => {
            pack_fano_xor_payload_route_with_hint(
                hint,
                FANO_XOR_ROUTE_ADMITTED,
                payload,
                aeon_gate[0],
                aeon_gate[1],
            )
        }
        MonsterFanoXorPayloadRoute::SameAeonPhase { phase } => {
            pack_fano_xor_payload_route_with_hint(hint, FANO_XOR_ROUTE_SAME_PHASE, phase, 0, 0)
        }
        MonsterFanoXorPayloadRoute::OutsideFanoSubatlas { aeon_gate } => {
            pack_fano_xor_payload_route_with_hint(
                hint,
                FANO_XOR_ROUTE_OUTSIDE_SUBATLAS,
                0,
                aeon_gate[0],
                aeon_gate[1],
            )
        }
        MonsterFanoXorPayloadRoute::ShadowValidationRequired { aeon_gate } => {
            pack_fano_xor_payload_route_with_hint(
                hint,
                FANO_XOR_ROUTE_SHADOW_REQUIRED,
                0,
                aeon_gate[0],
                aeon_gate[1],
            )
        }
    }
}

#[inline(always)]
pub fn fano_xor_payload_route_unpack(route: u16) -> MonsterFanoXorPayloadRoute {
    match fano_xor_payload_route_status(route) {
        FANO_XOR_ROUTE_ADMITTED => MonsterFanoXorPayloadRoute::Admitted {
            payload: fano_xor_payload_route_value(route),
            aeon_gate: fano_xor_payload_route_gate(route),
        },
        FANO_XOR_ROUTE_SAME_PHASE => MonsterFanoXorPayloadRoute::SameAeonPhase {
            phase: fano_xor_payload_route_value(route),
        },
        FANO_XOR_ROUTE_OUTSIDE_SUBATLAS => MonsterFanoXorPayloadRoute::OutsideFanoSubatlas {
            aeon_gate: fano_xor_payload_route_gate(route),
        },
        FANO_XOR_ROUTE_SHADOW_REQUIRED => MonsterFanoXorPayloadRoute::ShadowValidationRequired {
            aeon_gate: fano_xor_payload_route_gate(route),
        },
        _ => unreachable!("route status is packed into two bits"),
    }
}

#[inline(always)]
pub fn route_monster_fano_xor_payload_packed_with_hint(
    lhs_column: u32,
    rhs_column: u32,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> u16 {
    let route = route_monster_fano_xor_payload(
        lhs_column,
        rhs_column,
        residual_validated,
        fingerprint_verified,
    );
    pack_monster_fano_xor_payload_route_with_hint(lhs_column, rhs_column, route)
}

#[inline(always)]
pub fn route_monster_fano_xor_payload_packed(
    lhs_column: u32,
    rhs_column: u32,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> u16 {
    let lhs_phase = monster_column_phase(lhs_column);
    let rhs_phase = monster_column_phase(rhs_column);

    if lhs_phase == rhs_phase {
        return pack_fano_xor_payload_route(FANO_XOR_ROUTE_SAME_PHASE, lhs_phase, 0, 0);
    }

    let (gate0, gate1) = if lhs_phase < rhs_phase {
        (lhs_phase, rhs_phase)
    } else {
        (rhs_phase, lhs_phase)
    };

    if lhs_phase >= AEON_FANO_VISIBLE_PHASES || rhs_phase >= AEON_FANO_VISIBLE_PHASES {
        return pack_fano_xor_payload_route(FANO_XOR_ROUTE_OUTSIDE_SUBATLAS, 0, gate0, gate1);
    }

    if !(residual_validated && fingerprint_verified) {
        return pack_fano_xor_payload_route(FANO_XOR_ROUTE_SHADOW_REQUIRED, 0, gate0, gate1);
    }

    pack_fano_xor_payload_route(
        FANO_XOR_ROUTE_ADMITTED,
        triton_collide(lhs_phase + 1, rhs_phase + 1),
        gate0,
        gate1,
    )
}

pub fn monster_pair_fano_xor_runtime_stack(
    lhs_column: u32,
    rhs_column: u32,
) -> Option<[Option<u8>; AEON_GR_2_12_GATE_COUNT]> {
    let lhs_phase = monster_column_phase(lhs_column);
    let rhs_phase = monster_column_phase(rhs_column);
    if lhs_phase == rhs_phase {
        return None;
    }

    let (Some(lhs_state), Some(rhs_state)) = (
        aeon_phase_to_fano_state(lhs_phase),
        aeon_phase_to_fano_state(rhs_phase),
    ) else {
        return None;
    };

    let lhs = FanoPoint::new(lhs_state).expect("phase-to-state maps to a visible Fano point");
    let rhs = FanoPoint::new(rhs_state).expect("phase-to-state maps to a visible Fano point");
    fano_pair_xor_runtime_stack(lhs, rhs).ok()
}

#[inline(always)]
pub fn monster_pair_fano_xor_payload(lhs_column: u32, rhs_column: u32) -> Option<u8> {
    let lhs_phase = monster_column_phase(lhs_column);
    let rhs_phase = monster_column_phase(rhs_column);
    if lhs_phase == rhs_phase
        || lhs_phase >= AEON_FANO_VISIBLE_PHASES
        || rhs_phase >= AEON_FANO_VISIBLE_PHASES
    {
        return None;
    }

    Some(triton_collide(lhs_phase + 1, rhs_phase + 1))
}

pub fn fano_oriented_pair_certificate(
    lhs: FanoPoint,
    rhs: FanoPoint,
) -> Result<FanoOrientedPairCertificate, FanoRuntimeError> {
    if lhs == rhs {
        return Err(FanoRuntimeError::SelfCollisionExitsToRoot);
    }
    let lhs_column = lhs.aeon_column();
    let rhs_column = rhs.aeon_column();
    let sorted_gate = if lhs_column < rhs_column {
        [lhs_column, rhs_column]
    } else {
        [rhs_column, lhs_column]
    };
    let orientation_sign = if lhs_column < rhs_column { 1 } else { -1 };
    Ok(FanoOrientedPairCertificate {
        oriented_gate: [lhs_column, rhs_column],
        sorted_gate,
        orientation_sign,
        positive_gate: true,
        completion: triton_collide(lhs.state(), rhs.state()),
    })
}

pub fn fano_residual_shadow_certificate(
    fingerprint: u8,
    validated: bool,
) -> Result<FanoResidualShadowCertificate, FanoRuntimeError> {
    if fingerprint > 7 {
        return Err(FanoRuntimeError::OutOfCarrier(fingerprint));
    }
    Ok(FanoResidualShadowCertificate {
        fingerprint,
        validated,
        visible_seed: fingerprint != GOD_POSITION,
        routed_seed: fingerprint,
    })
}

#[inline(always)]
pub const fn fano_completion_cache_key(lhs_state: u8, rhs_state: u8) -> u8 {
    ((lhs_state & 0b111) << 3) | (rhs_state & 0b111)
}

#[inline(always)]
pub const fn fano_aeon_phase_cache_key(
    lhs_phase: u8,
    rhs_phase: u8,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> u16 {
    let flags = (residual_validated as u16) | ((fingerprint_verified as u16) << 1);
    (((lhs_phase as u16) * (AEON_GR_2_12_AMBIENT_DIM as u16) + rhs_phase as u16) << 2) | flags
}

#[inline(always)]
pub const fn fano_monster_pair_cache_key(
    lhs_column: u32,
    rhs_column: u32,
    residual_validated: bool,
    fingerprint_verified: bool,
) -> u64 {
    let flags = (residual_validated as u64) | ((fingerprint_verified as u64) << 1);
    (((lhs_column as u64) * (MONSTER_MOONSHINE_DIM as u64) + rhs_column as u64) << 2) | flags
}

/// Admission gate for using the Fano XOR runtime.
///
/// The gate is deliberately narrower than the kernel:
/// - direct admission is only for operations already projected to the binary
///   projective shadow;
/// - residual-seed routes stay `ShadowOnly` until fingerprint validation has
///   passed;
/// - Plucker sign lifts and positive gate claims can enter only as validated
///   Fano shadows: XOR completion plus the relevant finite certificate bits;
/// - full Grassmannian transforms are denied until a separate adapter proves
///   which structure survives projection to this Fano shadow.
pub fn admit_fano_runtime(request: &FanoAdmissionRequest) -> FanoAdmissionWitness {
    let theorem_refs = FANO_RUNTIME_THEOREM_REFS;

    if request.lhs > 7 || request.rhs > 7 {
        return FanoAdmissionWitness {
            decision: FanoAdmissionDecision::Deny,
            reason: FanoAdmissionReason::OutOfCarrier,
            collision: None,
            pair_gate: None,
            oriented_pair: None,
            residual_shadow: None,
            theorem_refs,
        };
    }

    if request.lhs == GOD_POSITION || request.rhs == GOD_POSITION {
        let collision = fano_collision(request.lhs, request.rhs).ok();
        return FanoAdmissionWitness {
            decision: FanoAdmissionDecision::Deny,
            reason: FanoAdmissionReason::RootOperand,
            collision,
            pair_gate: None,
            oriented_pair: None,
            residual_shadow: None,
            theorem_refs,
        };
    }

    let collision = fano_collision(request.lhs, request.rhs).ok();
    if request.lhs == request.rhs {
        return FanoAdmissionWitness {
            decision: FanoAdmissionDecision::Deny,
            reason: FanoAdmissionReason::SelfCollisionExitsToRoot,
            collision,
            pair_gate: None,
            oriented_pair: None,
            residual_shadow: None,
            theorem_refs,
        };
    }

    let pair_gate = match (FanoPoint::new(request.lhs), FanoPoint::new(request.rhs)) {
        (Ok(lhs), Ok(rhs)) => fano_pair_gate(lhs, rhs).ok(),
        _ => None,
    };
    let oriented_pair = match (FanoPoint::new(request.lhs), FanoPoint::new(request.rhs)) {
        (Ok(lhs), Ok(rhs)) => fano_oriented_pair_certificate(lhs, rhs).ok(),
        _ => None,
    };
    let residual_shadow = fano_residual_shadow_certificate(
        triton_collide(request.lhs, request.rhs),
        request.shadow_validation,
    )
    .ok();

    match request.op {
        FanoOperationKind::BinaryProjectiveRoute => FanoAdmissionWitness {
            decision: FanoAdmissionDecision::AdmitXor,
            reason: FanoAdmissionReason::BinaryProjectiveShadow,
            collision,
            pair_gate,
            oriented_pair: None,
            residual_shadow: None,
            theorem_refs,
        },
        FanoOperationKind::ResidualSeedShadow => {
            if request.shadow_validation && request.fingerprint_verified {
                FanoAdmissionWitness {
                    decision: FanoAdmissionDecision::AdmitXor,
                    reason: FanoAdmissionReason::BinaryProjectiveShadow,
                    collision,
                    pair_gate,
                    oriented_pair: None,
                    residual_shadow,
                    theorem_refs,
                }
            } else {
                FanoAdmissionWitness {
                    decision: FanoAdmissionDecision::ShadowOnly,
                    reason: FanoAdmissionReason::ShadowValidationRequired,
                    collision,
                    pair_gate,
                    oriented_pair: None,
                    residual_shadow,
                    theorem_refs,
                }
            }
        }
        FanoOperationKind::PluckerSignLift => {
            if request.shadow_validation && request.fingerprint_verified {
                FanoAdmissionWitness {
                    decision: FanoAdmissionDecision::AdmitXor,
                    reason: FanoAdmissionReason::PluckerSignShadow,
                    collision,
                    pair_gate,
                    oriented_pair,
                    residual_shadow: None,
                    theorem_refs,
                }
            } else {
                FanoAdmissionWitness {
                    decision: FanoAdmissionDecision::ShadowOnly,
                    reason: FanoAdmissionReason::ShadowValidationRequired,
                    collision,
                    pair_gate,
                    oriented_pair,
                    residual_shadow: None,
                    theorem_refs,
                }
            }
        }
        FanoOperationKind::PositiveGateShadow => {
            if request.shadow_validation && request.fingerprint_verified {
                FanoAdmissionWitness {
                    decision: FanoAdmissionDecision::AdmitXor,
                    reason: FanoAdmissionReason::PositiveGateShadow,
                    collision,
                    pair_gate,
                    oriented_pair,
                    residual_shadow: None,
                    theorem_refs,
                }
            } else {
                FanoAdmissionWitness {
                    decision: FanoAdmissionDecision::ShadowOnly,
                    reason: FanoAdmissionReason::ShadowValidationRequired,
                    collision,
                    pair_gate,
                    oriented_pair,
                    residual_shadow: None,
                    theorem_refs,
                }
            }
        }
        FanoOperationKind::FullGrassmannianTransform => FanoAdmissionWitness {
            decision: FanoAdmissionDecision::Deny,
            reason: FanoAdmissionReason::HigherStructureNotProjected,
            collision,
            pair_gate,
            oriented_pair: None,
            residual_shadow: None,
            theorem_refs,
        },
    }
}

/// Slow baseline used only for benchmark attribution. It scans the 21 visible
/// unordered pairs instead of using the XOR completion directly.
#[inline(never)]
pub fn complete_by_pair_scan(lhs: u8, rhs: u8) -> Result<u8, FanoRuntimeError> {
    let lhs = FanoPoint::new(lhs)?;
    let rhs = FanoPoint::new(rhs)?;
    if lhs == rhs {
        return Err(FanoRuntimeError::SelfCollisionExitsToRoot);
    }
    for a in VISIBLE_FANO_POINTS {
        for b in VISIBLE_FANO_POINTS {
            if a >= b {
                continue;
            }
            if (a == lhs.state() && b == rhs.state()) || (a == rhs.state() && b == lhs.state()) {
                return Ok(triton_collide(a, b));
            }
        }
    }
    unreachable!("all distinct visible pairs are covered by the 21 Fano pair gates")
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct PairXScheduleConfig {
    pub layers: u32,
    pub attn_ns: u64,
    pub gate_ns: u64,
    pub down_ns: u64,
    pub jump_ns: u64,
}

#[derive(Clone, Copy, Debug, PartialEq)]
pub struct PairXScheduleEstimate {
    pub sequential_ns: u64,
    pub fano_shadow_ns: u64,
    pub saved_ns: u64,
    pub speedup: f64,
}

/// Synthetic scheduler for the Pair-X claim in `OCTONION_ROUTING_PLAN.md`.
///
/// Sequential baseline: each layer runs ATTN -> GATE -> DOWN.
/// Fano shadow: the input seed for layer `l + 1` can arrive by XOR-routed
/// jump from layer `l`'s already-known residual seed. The full residual still
/// validates through the canonical chain; this only models when the next ATTN
/// can start in shadow/benchmark mode.
pub fn estimate_pair_x_schedule(config: PairXScheduleConfig) -> PairXScheduleEstimate {
    if config.layers == 0 {
        return PairXScheduleEstimate {
            sequential_ns: 0,
            fano_shadow_ns: 0,
            saved_ns: 0,
            speedup: 1.0,
        };
    }

    let per_layer = config.attn_ns + config.gate_ns + config.down_ns;
    let sequential_ns = u64::from(config.layers).saturating_mul(per_layer);

    let mut seed_ready_ns = 0u64;
    let mut final_down_end_ns = 0u64;
    for _layer in 0..config.layers {
        let attn_start_ns = seed_ready_ns;
        let attn_end_ns = attn_start_ns + config.attn_ns;
        let gate_end_ns = attn_end_ns + config.gate_ns;
        let down_end_ns = gate_end_ns + config.down_ns;
        final_down_end_ns = final_down_end_ns.max(down_end_ns);
        seed_ready_ns = attn_start_ns + config.jump_ns;
    }

    let saved_ns = sequential_ns.saturating_sub(final_down_end_ns);
    let speedup = if final_down_end_ns == 0 {
        1.0
    } else {
        sequential_ns as f64 / final_down_end_ns as f64
    };

    PairXScheduleEstimate {
        sequential_ns,
        fano_shadow_ns: final_down_end_ns,
        saved_ns,
        speedup,
    }
}

