pub fn benchmark_fano_kernel(iterations: u64) -> FanoKernelBenchReport {
    let iterations = iterations.max(1);
    let mut states = 0x9E37_79B9_7F4A_7C15u64;
    let mut checksum = 0u64;

    let xor_start = Instant::now();
    for _ in 0..iterations {
        states = states
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        let lhs = ((states >> 8) as u8 % 7) + 1;
        let rhs_seed = ((states >> 17) as u8 % 6) + 1;
        let rhs = if rhs_seed >= lhs {
            rhs_seed + 1
        } else {
            rhs_seed
        };
        checksum = checksum.wrapping_add(u64::from(triton_collide(lhs, rhs)));
    }
    let xor_duration = xor_start.elapsed();

    let mut states = 0x9E37_79B9_7F4A_7C15u64;
    let scan_start = Instant::now();
    for _ in 0..iterations {
        states = states
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        let lhs = ((states >> 8) as u8 % 7) + 1;
        let rhs_seed = ((states >> 17) as u8 % 6) + 1;
        let rhs = if rhs_seed >= lhs {
            rhs_seed + 1
        } else {
            rhs_seed
        };
        checksum = checksum.wrapping_add(u64::from(
            complete_by_pair_scan(lhs, rhs).expect("generated pair is visible and distinct"),
        ));
    }
    let scan_duration = scan_start.elapsed();

    let mut states = 0x9E37_79B9_7F4A_7C15u64;
    let stack_start = Instant::now();
    for _ in 0..iterations {
        states = states
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        let lhs = ((states >> 8) as u8 % 7) + 1;
        let rhs_seed = ((states >> 17) as u8 % 6) + 1;
        let rhs = if rhs_seed >= lhs {
            rhs_seed + 1
        } else {
            rhs_seed
        };
        let lhs = FanoPoint::new(lhs).expect("generated lhs is visible");
        let rhs = FanoPoint::new(rhs).expect("generated rhs is visible");
        let stack = fano_pair_xor_runtime_stack(lhs, rhs).expect("generated pair is distinct");
        checksum = checksum.wrapping_add(
            stack
                .iter()
                .flatten()
                .map(|payload| u64::from(*payload))
                .sum::<u64>(),
        );
    }
    let stack_duration = stack_start.elapsed();

    let xor_secs = xor_duration.as_secs_f64().max(f64::EPSILON);
    let scan_secs = scan_duration.as_secs_f64().max(f64::EPSILON);
    let stack_secs = stack_duration.as_secs_f64().max(f64::EPSILON);
    let xor_routes_per_second = iterations as f64 / xor_secs;
    let scan_routes_per_second = iterations as f64 / scan_secs;
    let stack_routes_per_second = iterations as f64 / stack_secs;
    let speedup = scan_secs / xor_secs;
    let stack_speedup = stack_secs / xor_secs;

    FanoKernelBenchReport {
        iterations,
        xor_duration,
        scan_duration,
        stack_duration,
        xor_routes_per_second,
        scan_routes_per_second,
        stack_routes_per_second,
        speedup,
        stack_speedup,
        checksum,
    }
}

pub fn benchmark_fano_admission(iterations: u64) -> FanoAdmissionBenchReport {
    let iterations = iterations.max(1);
    let mut states = 0xD1B5_4A32_D192_ED03u64;
    let mut admitted = 0u64;
    let mut shadow_only = 0u64;
    let mut denied = 0u64;
    let mut checksum = 0u64;

    let started = Instant::now();
    for index in 0..iterations {
        states = states
            .wrapping_mul(2862933555777941757)
            .wrapping_add(3037000493);
        let lhs = ((states >> 9) as u8) & 0b111;
        let rhs = ((states >> 19) as u8) & 0b111;
        let op = match index % 8 {
            0..=3 => FanoOperationKind::BinaryProjectiveRoute,
            4 | 5 => FanoOperationKind::ResidualSeedShadow,
            6 => FanoOperationKind::PluckerSignLift,
            7 => FanoOperationKind::PositiveGateShadow,
            _ => FanoOperationKind::FullGrassmannianTransform,
        };
        let (shadow_validation, fingerprint_verified) = match op {
            FanoOperationKind::PluckerSignLift => (index % 16 == 6, index % 32 == 6),
            FanoOperationKind::PositiveGateShadow => (index % 16 == 7, index % 32 == 7),
            _ => (index % 4 == 0, index % 16 == 0),
        };
        let witness = admit_fano_runtime(&FanoAdmissionRequest {
            op,
            lhs,
            rhs,
            shadow_validation,
            fingerprint_verified,
        });
        match witness.decision {
            FanoAdmissionDecision::AdmitXor => admitted += 1,
            FanoAdmissionDecision::ShadowOnly => shadow_only += 1,
            FanoAdmissionDecision::Deny => denied += 1,
        }
        if let Some(collision) = witness.collision {
            checksum = checksum.wrapping_add(u64::from(collision.completion));
        }
        if let Some(pair_gate) = witness.pair_gate {
            checksum = checksum.wrapping_add(u64::from(pair_gate[0]) + u64::from(pair_gate[1]));
        }
        if let Some(oriented_pair) = witness.oriented_pair {
            checksum = checksum
                .wrapping_add(u64::from(oriented_pair.completion))
                .wrapping_add(oriented_pair.orientation_sign.unsigned_abs().into())
                .wrapping_add(u64::from(oriented_pair.positive_gate));
        }
        if let Some(residual_shadow) = witness.residual_shadow {
            checksum = checksum
                .wrapping_add(u64::from(residual_shadow.routed_seed))
                .wrapping_add(u64::from(residual_shadow.visible_seed))
                .wrapping_add(u64::from(residual_shadow.validated));
        }
    }
    let duration = started.elapsed();
    let seconds = duration.as_secs_f64().max(f64::EPSILON);
    FanoAdmissionBenchReport {
        iterations,
        duration,
        decisions_per_second: iterations as f64 / seconds,
        admitted,
        shadow_only,
        denied,
        checksum,
    }
}

