        assert_eq!(stats.aeon_misses, 0);
        assert_eq!(stats.aeon_hits, 0);
        assert_eq!(stats.monster_misses, 0);
        assert_eq!(stats.monster_hits, 0);
        assert_eq!(stats.monster_entries, 0);
