        let report = benchmark_monster_fano_xor_runtime_stack(10_000);

        assert_eq!(report.iterations, 10_000);
        assert!(report.compact_payload_routes_per_second > 0.0);
        assert_eq!(report.compact_payload_admitted, report.payload_admitted);
        assert_eq!(report.compact_payload_same_phase, report.payload_same_phase);
        assert_eq!(
            report.compact_payload_outside_fano_subatlas,
            report.payload_outside_fano_subatlas
        );
        assert_eq!(
            report.compact_payload_shadow_validation_required,
            report.payload_shadow_validation_required
        );
        assert!(report.packed_payload_routes_per_second > 0.0);
        assert_eq!(report.packed_payload_admitted, report.payload_admitted);
        assert_eq!(report.packed_payload_same_phase, report.payload_same_phase);
        assert_eq!(
            report.packed_payload_outside_fano_subatlas,
            report.payload_outside_fano_subatlas
        );
        assert_eq!(
            report.packed_payload_shadow_validation_required,
            report.payload_shadow_validation_required
        );
        assert!(report.policy_random_payload_routes_per_second > 0.0);
        assert_eq!(
            report.policy_random_payload_admitted,
            report.payload_admitted
        );
        assert!(report.policy_hot_payload_routes_per_second > 0.0);
        assert_eq!(report.policy_hot_payload_admitted, 10_000);
        assert_eq!(report.policy_hot_payload_stats.fano_route_hits, 9994);
        assert_eq!(report.policy_hot_payload_stats.payload_monster_hits, 0);
        assert!(report.policy_hot_packed_payload_routes_per_second > 0.0);
        assert_eq!(report.policy_hot_packed_payload_admitted, 10_000);
        assert_eq!(report.policy_hot_packed_payload_stats.fano_route_hits, 9994);
        assert_eq!(report.policy_hot_packed_payload_stats.fano_route_misses, 6);
        assert!(report.default_packed_payload_routes_per_second > 0.0);
        assert_eq!(report.default_packed_payload_admitted, 10_000);
        assert_eq!(report.default_packed_payload_stats.fano_route_hits, 9994);
        assert_eq!(report.default_packed_payload_stats.fano_route_misses, 6);
        assert!(report.cached_payload_admissions_per_second > 0.0);
        assert_eq!(report.cached_payload_admitted, 10_000);
        assert_eq!(report.cached_payload_same_phase, 0);
        assert_eq!(report.cached_payload_outside_fano_subatlas, 0);
        assert_eq!(report.cached_payload_shadow_validation_required, 0);
        assert!(report.cached_payload_stats.fano_route_hits > 0);
        assert!(report.cached_payload_stats.fano_route_misses <= 6);
        assert_eq!(report.cached_payload_stats.aeon_hits, 0);
        assert_eq!(report.cached_payload_stats.aeon_misses, 0);
        assert_eq!(report.cached_payload_stats.payload_monster_misses, 0);
        assert_eq!(report.cached_payload_stats.payload_monster_entries, 0);
        assert_eq!(report.hot_cached_payload_admitted, 10_000);
